+    fn validate_local_closure(&self, touched: &BTreeSet<PaneId>) -> Result<(), PaneModelError> {
+        for node_id in touched {
+            let node = self
+                .nodes
+                .get(node_id)
+                .ok_or(PaneModelError::MissingRoot { root: *node_id })?;
+            node.constraints.validate(*node_id)?;
+
